// Family 11 — Enrichment / FriendlyText + MockData.
//
// The FriendlyText<T> + MockData<T> mirrors this imports are AUTOGENERATED by
// `ts-runtypes gen` into src/__runtypes/enriched/{friendly,mock,i18n}/ — never
// hand-written, never next to the model (src/models/enriched-user.ts). In a real
// project those generated files are COMMITTED (authored once, then validated
// against the type forever); in THIS fixture they are gitignored and the e2e
// regenerates them fresh each run (via the published `ts-runtypes` CLI) so the
// test exercises the generator itself. So these imports only resolve AFTER
// `ts-runtypes gen` has run — the e2e does that before building (see
// scripts/release/e2e.mjs) and the host smoke does it in build-all's preflight.
import {createFriendlyText, createFriendlyTextI18n, createGetValidationErrors, createMockData} from '@ts-runtypes/core';
import {type CheckResult, ok} from './check';
import type {EnrichedUser} from './models/enriched-user';
import {friendlyEnrichedUser} from '../runtypes/generated/friendly/models/enriched-user';
import {mockEnrichedUser} from '../runtypes/generated/mock/models/enriched-user';
import {es_friendlyEnrichedUser} from '../runtypes/generated/i18n/es/models/enriched-user';

const getUserErrors = createGetValidationErrors<EnrichedUser>();

export const friendly = createFriendlyText<EnrichedUser>(friendlyEnrichedUser);
export const friendlyEs = createFriendlyTextI18n<EnrichedUser>(friendlyEnrichedUser, {locale: 'es', translations: {es: es_friendlyEnrichedUser}});
export const mockUser = createMockData<EnrichedUser>(undefined, {data: mockEnrichedUser});

// NOTE: the mirrors here are FRESHLY-SCAFFOLDED by `ts-runtypes gen` (empty
// `@todo` pools + labels — a real author fills them). So these assertions test
// the end-to-end WIRING (the published package + the autogenerated mirrors feed
// the runtime factories, which run + produce the right SHAPES), NOT filled
// content — an unfilled scaffold deliberately can't satisfy format constraints
// (e.g. name's minLength), so "mock passes validate" is not asserted here.
// Family 10 (mocking.ts) covers format-valid mocking from the type.
export function checkEnrichment(): CheckResult[] {
  const badInput: unknown = {name: 'A', age: -5, isActive: 'nope', tags: 'x'};
  const errs = getUserErrors(badInput);
  const rendered = friendly.errors(errs);
  const renderedEs = friendlyEs.errors(errs);
  const label = friendly.label('name');
  const sample = mockUser();
  return [
    ok('enrichment: autogenerated FriendlyText + MockData mirrors import + wire up', typeof friendlyEnrichedUser === 'object' && typeof mockEnrichedUser === 'object'),
    // The data-driven mock generator runs over the mirror + the type graph and
    // emits a value with every declared field, correctly typed.
    ok('enrichment: createMockData({data}) emits a shaped value for the type', typeof sample.name === 'string' && typeof sample.age === 'number' && Array.isArray(sample.tags)),
    // createFriendlyText + the i18n locale-selecting twin run against the mirrors.
    ok('enrichment: createFriendlyText renders an errors array + resolves a label', Array.isArray(rendered) && typeof label === 'string'),
    ok('enrichment: rendered friendly messages are strings', rendered.every((entry) => typeof entry.message === 'string')),
    ok('enrichment: createFriendlyTextI18n(es) renders without error', Array.isArray(renderedEs)),
  ];
}
